sed -i '/<div className="grid grid-cols-2 gap-3">/i \
          <div className="mb-3">\n            <label className="block text-[11px] font-medium text-[#6B7280] mb-1">Company Logo<\/label>\n            <div className="flex items-center gap-3">\n              {invoice.company.logoUrl && (\n                <div className="w-10 h-10 rounded border border-[#E5E7EB] overflow-hidden flex-shrink-0">\n                  <img src={invoice.company.logoUrl} alt="Logo" className="w-full h-full object-contain bg-white" \/>\n                <\/div>\n              )}\n              <input type="file" accept="image/*" onChange={(e) => {\n                const file = e.target.files?.[0];\n                if (file) {\n                  const reader = new FileReader();\n                  reader.onload = (event) => {\n                    updateCompany("logoUrl", event.target?.result as string);\n                  };\n                  reader.readAsDataURL(file);\n                }\n              }} className="w-full text-[11px] file:mr-3 file:py-1.5 file:px-3 file:rounded file:border-0 file:text-[11px] file:font-medium file:bg-[#1F6F50]\/10 file:text-[#1F6F50] hover:file:bg-[#1F6F50]\/20 transition-colors" \/>\n              {invoice.company.logoUrl && (\n                <button onClick={() => updateCompany("logoUrl", "")} className="text-[#6B7280] hover:text-red-500 text-[11px]">\n                  Remove\n                <\/button>\n              )}\n            <\/div>\n          <\/div>' src/components/InvoiceBuilder.tsx
